15	type GeneratedBundledChannelEntry = {
16	  id: string;
17	  entry: {
18	    channelPlugin: ChannelPlugin;
19	    setChannelRuntime?: (runtime: PluginRuntime) => void;
20	  };
21	  setupEntry?: {
22	    plugin: ChannelPlugin;
23	  };
24	};
