26	const log = createSubsystemLogger("channels");
27	
28	function resolveChannelPluginModuleEntry(
29	  moduleExport: unknown,
30	): GeneratedBundledChannelEntry["entry"] | null {
31	  const resolved =
32	    moduleExport &&
33	    typeof moduleExport === "object" &&
34	    "default" in (moduleExport as Record<string, unknown>)
35	      ? (moduleExport as { default: unknown }).default
36	      : moduleExport;
37	  if (!resolved || typeof resolved !== "object") {
38	    return null;
39	  }
40	  const record = resolved as {
41	    channelPlugin?: unknown;
42	    setChannelRuntime?: unknown;
43	  };
44	  if (!record.channelPlugin || typeof record.channelPlugin !== "object") {
45	    return null;
46	  }
47	  return {
48	    channelPlugin: record.channelPlugin as ChannelPlugin,
49	    ...(typeof record.setChannelRuntime === "function"
50	      ? { setChannelRuntime: record.setChannelRuntime as (runtime: PluginRuntime) => void }
51	      : {}),
52	  };
53	}
54	
55	function resolveChannelSetupModuleEntry(
56	  moduleExport: unknown,
57	): GeneratedBundledChannelEntry["setupEntry"] | null {
58	  const resolved =
59	    moduleExport &&
60	    typeof moduleExport === "object" &&
61	    "default" in (moduleExport as Record<string, unknown>)
62	      ? (moduleExport as { default: unknown }).default
63	      : moduleExport;
64	  if (!resolved || typeof resolved !== "object") {
65	    return null;
66	  }
67	  const record = resolved as {
68	    plugin?: unknown;
69	  };
70	  if (!record.plugin || typeof record.plugin !== "object") {
71	    return null;
72	  }
73	  return {
74	    plugin: record.plugin as ChannelPlugin,
75	  };
76	}
