78	function createModuleLoader() {
79	  const jitiLoaders = new Map<string, ReturnType<typeof createJiti>>();
80	
81	  return (modulePath: string) => {
82	    const tryNative = shouldPreferNativeJiti(modulePath);
83	    const aliasMap = buildPluginLoaderAliasMap(modulePath, process.argv[1], import.meta.url);
84	    const cacheKey = JSON.stringify({
85	      tryNative,
86	      aliasMap: Object.entries(aliasMap).toSorted(([left], [right]) => left.localeCompare(right)),
87	    });
88	    const cached = jitiLoaders.get(cacheKey);
89	    if (cached) {
90	      return cached;
91	    }
92	    const loader = createJiti(import.meta.url, {
93	      ...buildPluginLoaderJitiOptions(aliasMap),
94	      tryNative,
95	    });
96	    jitiLoaders.set(cacheKey, loader);
97	    return loader;
98	  };
99	}
100	
101	const loadModule = createModuleLoader();
102	
103	function loadBundledModule(modulePath: string, rootDir: string): unknown {
104	  const opened = openBoundaryFileSync({
105	    absolutePath: modulePath,
106	    rootPath: rootDir,
107	    boundaryLabel: "plugin root",
108	    rejectHardlinks: false,
109	    skipLexicalRootCheck: true,
110	  });
111	  if (!opened.ok) {
112	    throw new Error("plugin entry path escapes plugin root or fails alias checks");
113	  }
114	  const safePath = opened.path;
115	  fs.closeSync(opened.fd);
116	  return loadModule(safePath)(safePath);
117	}
118	
119	function loadGeneratedBundledChannelEntries(): readonly GeneratedBundledChannelEntry[] {
120	  const discovery = discoverOpenClawPlugins({ cache: false });
121	  const manifestRegistry = loadPluginManifestRegistry({
122	    cache: false,
123	    config: {},
124	    candidates: discovery.candidates,
125	    diagnostics: discovery.diagnostics,
126	  });
127	  const manifestByRoot = new Map(
128	    manifestRegistry.plugins.map((plugin) => [plugin.rootDir, plugin] as const),
129	  );
130	  const seenIds = new Set<string>();
131	  const entries: GeneratedBundledChannelEntry[] = [];
132	
133	  for (const candidate of discovery.candidates) {
134	    const manifest = manifestByRoot.get(candidate.rootDir);
135	    if (!manifest || manifest.origin !== "bundled" || manifest.channels.length === 0) {
136	      continue;
137	    }
138	    if (seenIds.has(manifest.id)) {
139	      continue;
140	    }
141	    seenIds.add(manifest.id);
142	
143	    try {
144	      const entry = resolveChannelPluginModuleEntry(
145	        loadBundledModule(candidate.source, candidate.rootDir),
146	      );
147	      if (!entry) {
148	        log.warn(
149	          `[channels] bundled channel entry ${manifest.id} missing channelPlugin export; skipping`,
150	        );
151	        continue;
152	      }
153	      const setupEntry = manifest.setupSource
154	        ? resolveChannelSetupModuleEntry(loadBundledModule(manifest.setupSource, candidate.rootDir))
155	        : null;
156	      entries.push({
157	        id: manifest.id,
158	        entry,
159	        ...(setupEntry ? { setupEntry } : {}),
160	      });
161	    } catch (error) {
162	      log.warn(
163	        `[channels] failed to load bundled channel ${manifest.id} from ${candidate.source}: ${String(error)}`,
164	      );
165	    }
166	  }
167	
168	  return entries;
169	}
170	
171	function buildBundledChannelPluginsById(plugins: readonly ChannelPlugin[]) {
172	  const byId = new Map<ChannelId, ChannelPlugin>();
173	  for (const plugin of plugins) {
174	    if (byId.has(plugin.id)) {
175	      throw new Error(`duplicate bundled channel plugin id: ${plugin.id}`);
176	    }
177	    byId.set(plugin.id, plugin);
178	  }
179	  return byId;
180	}
181	
182	type BundledChannelState = {
183	  entries: readonly GeneratedBundledChannelEntry[];
184	  plugins: readonly ChannelPlugin[];
185	  setupPlugins: readonly ChannelPlugin[];
186	  pluginsById: Map<ChannelId, ChannelPlugin>;
187	  runtimeSettersById: Map<
188	    ChannelId,
189	    NonNullable<GeneratedBundledChannelEntry["entry"]["setChannelRuntime"]>
190	  >;
191	};
192	
193	let cachedBundledChannelState: BundledChannelState | null = null;
194	
195	function getBundledChannelState(): BundledChannelState {
196	  if (cachedBundledChannelState) {
197	    return cachedBundledChannelState;
198	  }
199	
200	  const entries = loadGeneratedBundledChannelEntries();
201	  const plugins = entries.map(({ entry }) => entry.channelPlugin);
202	  const setupPlugins = entries.flatMap(({ setupEntry }) => {
203	    const plugin = setupEntry?.plugin;
204	    return plugin ? [plugin] : [];
205	  });
206	  const runtimeSettersById = new Map<
207	    ChannelId,
208	    NonNullable<GeneratedBundledChannelEntry["entry"]["setChannelRuntime"]>
209	  >();
210	  for (const { entry } of entries) {
211	    if (entry.setChannelRuntime) {
212	      runtimeSettersById.set(entry.channelPlugin.id, entry.setChannelRuntime);
213	    }
214	  }
215	
216	  cachedBundledChannelState = {
217	    entries,
218	    plugins,
219	    setupPlugins,
220	    pluginsById: buildBundledChannelPluginsById(plugins),
221	    runtimeSettersById,
222	  };
223	  return cachedBundledChannelState;
224	}
225	
226	export function listBundledChannelPlugins(): readonly ChannelPlugin[] {
227	  return getBundledChannelState().plugins;
228	}
229	
230	export function listBundledChannelSetupPlugins(): readonly ChannelPlugin[] {
231	  return getBundledChannelState().setupPlugins;
232	}
233	
234	export function getBundledChannelPlugin(id: ChannelId): ChannelPlugin | undefined {
235	  return getBundledChannelState().pluginsById.get(id);
236	}
237	
238	export function requireBundledChannelPlugin(id: ChannelId): ChannelPlugin {
239	  const plugin = getBundledChannelPlugin(id);
240	  if (!plugin) {
241	    throw new Error(`missing bundled channel plugin: ${id}`);
242	  }
243	  return plugin;
244	}
245	
246	export function setBundledChannelRuntime(id: ChannelId, runtime: PluginRuntime): void {
247	  const setter = getBundledChannelState().runtimeSettersById.get(id);
248	  if (!setter) {
249	    throw new Error(`missing bundled channel runtime setter: ${id}`);
250	  }
251	  setter(runtime);
252	}
