53	function resolveDiscoveryCacheMs(env: NodeJS.ProcessEnv): number {
54	  const raw = env.OPENCLAW_PLUGIN_DISCOVERY_CACHE_MS?.trim();
55	  if (raw === "" || raw === "0") {
56	    return 0;
57	  }
58	  if (!raw) {
59	    return DEFAULT_DISCOVERY_CACHE_MS;
60	  }
61	  const parsed = Number.parseInt(raw, 10);
62	  if (!Number.isFinite(parsed)) {
63	    return DEFAULT_DISCOVERY_CACHE_MS;
64	  }
65	  return Math.max(0, parsed);
66	}
67	
68	function shouldUseDiscoveryCache(env: NodeJS.ProcessEnv): boolean {
69	  const disabled = env.OPENCLAW_DISABLE_PLUGIN_DISCOVERY_CACHE?.trim();
70	  if (disabled) {
71	    return false;
72	  }
73	  return resolveDiscoveryCacheMs(env) > 0;
74	}
