        });
        const resolveInboundAccess = async (senderPubkey: string, rawBody: string) =>
          await resolveNostrDirectAccess({
            cfg: ctx.cfg,
            accountId: account.accountId,
            dmPolicy: account.config.dmPolicy ?? "pairing",
            allowFrom: account.config.allowFrom,
