import type { CoreConfig } from "./types.js";
import {
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./accounts.js";

/**
 * Send a text message to a PulseBoard target (user or board).
 *
 * This is a stub implementation for the fictional PulseBoard platform.
 * A real implementation would call the PulseBoard HTTP API here.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts?: {
    cfg?: CoreConfig;
    accountId?: string;
    replyTo?: string;
  },
): Promise<{ messageId: string }> {
  let account: ResolvedPulseBoardAccount | undefined;
  if (opts?.cfg) {
    account = resolvePulseBoardAccount({ cfg: opts.cfg, accountId: opts.accountId });
  }

  if (account && !account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiUrl, username, and apiKey).`,
    );
  }

  // Stub: in a real implementation this would POST to the PulseBoard API.
  // POST ${account.apiUrl}/api/v1/messages
  // Headers: Authorization: Bearer ${account.apiKey}
  // Body: { to, text, replyTo: opts?.replyTo }
  const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  return { messageId };
}

