import type { BaseProbeResult } from "openclaw/plugin-sdk/channel-contract";
import type { DmPolicy, GroupPolicy, OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";

/** Per-board (group) configuration. */
export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

/** Account-level config for a single PulseBoard account. */
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** PulseBoard API endpoint URL. */
  apiUrl?: string;
  /** API key for authentication. */
  apiKey?: string;
  /** File path containing the API key. */
  apiKeyFile?: string;
  /** Bot username on PulseBoard. */
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Named board configurations. */
  boards?: Record<string, PulseBoardBoardConfig>;
  /** List of board names to join. */
  joinBoards?: string[];
  mentionPatterns?: string[];
  textChunkLimit?: number;
  responsePrefix?: string;
};

/** Top-level config shape at channels.pulseboard. */
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

/** Augmented OpenClawConfig with PulseBoard section. */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/** Inbound message from PulseBoard. */
export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation peer id: board name for groups, sender username for DMs. */
  target: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

/** Probe result for PulseBoard connection status. */
export type PulseBoardProbe = BaseProbeResult<string> & {
  apiUrl: string;
  username: string;
  latencyMs?: number;
};

