  "Env vars supported: PULSEBOARD_API_URL, PULSEBOARD_USERNAME, PULSEBOARD_API_KEY (default account only).",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),
  validateInput: ({ input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiUrl?: string;
      username?: string;
      apiKey?: string;
    };
    if (!typedInput.useEnv) {
      if (!typedInput.apiUrl?.trim()) {
        return "PulseBoard requires --api-url or --use-env.";
      }
      if (!typedInput.username?.trim()) {
        return "PulseBoard requires --username or --use-env.";
      }
      if (!typedInput.apiKey?.trim()) {
        return "PulseBoard requires --api-key or --use-env.";
      }
    }
    return null;
  },
  applyAccountConfig: ({ cfg, input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiUrl?: string;
      username?: string;
      apiKey?: string;
    };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      clearFields: typedInput.useEnv ? ["apiUrl", "username", "apiKey"] : undefined,
      patch: typedInput.useEnv
        ? {}
        : {
            apiUrl: typedInput.apiUrl?.trim(),
            username: typedInput.username?.trim(),
            apiKey: typedInput.apiKey?.trim(),
          },
    });
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API URL, username, and API key",
    configuredHint: "configured",
    unconfiguredHint: "needs credentials",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => resolvePulseBoardAccount({ cfg }).configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseBoardAccount({ cfg });
      if (!account.configured) {
        return [];
      }
      return [
        `API URL: ${account.apiUrl}`,
        `Username: ${account.username}`,
      ];
    },
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },
  envShortcut: {
    prompt: "PULSEBOARD_API_KEY detected. Use env vars?",
    preferredEnvVar: "PULSEBOARD_API_KEY",
    isAvailable: ({ cfg, accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID &&
      Boolean(process.env.PULSEBOARD_API_KEY?.trim()) &&
      !resolvePulseBoardAccount({ cfg, accountId }).configured,
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({
        cfg,
        channel,
        enabled: true,
        clearFields: ["apiUrl", "username", "apiKey"],
        patch: {},
      }),
  },
  credentials: [
    {
      inputKey: "apiKey",
      providerHint: channel,
      credentialLabel: "API key",
      preferredEnvVar: "PULSEBOARD_API_KEY",
      helpTitle: "PulseBoard API key",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_KEY detected. Use env var?",
      keepPrompt: "PulseBoard API key already configured. Keep it?",
      inputPrompt: "PulseBoard API key",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: Boolean(account.config.apiKey?.trim()),
          resolvedValue: account.apiKey,
          envValue: process.env.PULSEBOARD_API_KEY?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: ["apiKey"],
          patch: {},
        }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiKey: resolvedValue },
        }),
    },
  ],
  textInputs: [
    {
      inputKey: "apiUrl",
      message: "PulseBoard API URL",
      placeholder: "https://api.pulseboard.example.com",
      required: true,
      helpTitle: "PulseBoard API URL",
      helpLines: [
        "The base URL for the PulseBoard API.",
        "Example: https://api.pulseboard.example.com",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.apiUrl;
      },
      keepPrompt: (value) => `API URL set (${value}). Keep it?`,
      validate: ({ value }) => {
        try {
          const parsed = new URL(value);
          if (parsed.protocol !== "https:" && parsed.protocol !== "http:") {
            return "API URL must use http:// or https://";
          }
          return undefined;
        } catch {
          return "Invalid URL";
        }
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiUrl: value.trim() },
        }),
    },
    {
      inputKey: "username",
      message: "PulseBoard bot username",
      placeholder: "my-bot",
      required: true,
      helpTitle: "PulseBoard username",
      helpLines: [
        "The bot's username on PulseBoard.",
        "This is the identity used for sending and receiving messages.",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.username;
      },
      keepPrompt: (value) => `Username set (@${value}). Keep it?`,
      validate: ({ value }) => {
        const trimmed = value.trim().replace(/^@/, "");
        if (!trimmed) {
          return "Username is required";
        }
        if (!/^[\w][\w.-]{0,63}$/.test(trimmed)) {
          return "Username must be 1-64 alphanumeric characters, dots, or hyphens";
        }
        return undefined;
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { username: value.trim().replace(/^@/, "") },
        }),
    },
  ],
  disable: (cfg) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: { enabled: false },
    }),
};

